async (params, browser) => {
  // Open restaurant page
  await browser.open(`${params.restaurant_url}`)

  // Wait for restaurant page to load
  await browser.waitForSelector('h1#HEADING, [data-test-target=\'restaurant-detail-info\'], [class*=\'RestaurantHeader\']', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll to load more content
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract restaurant details
  const result = await browser.evaluate(`const nameEl = document.querySelector('h1#HEADING, h1[data-test-target="top-info-header"], h1[class*="restaurant"]'); const name = nameEl ? nameEl.textContent.trim() : ''; const ratingEl = document.querySelector('svg[aria-label*="bubble"], .ui_bubble_rating, [class*="ratingValue"]'); const rating = ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim() || '') : ''; const reviewCountEl = document.querySelector('a[href*="#REVIEWS"] span, [class*="reviewCount"], [data-test-target="review-count"]'); const reviewCount = reviewCountEl ? reviewCountEl.textContent.trim() : ''; const priceEl = document.querySelector('[class*="priceRange"], [class*="price"], .priceRange, [data-test-target="restaurant-detail-info"] [class*="price"]'); const priceRange = priceEl ? priceEl.textContent.trim() : ''; const rankEl = document.querySelector('[class*="ranking"], [data-test-target="restaurant-ranking"], .popRanking'); const ranking = rankEl ? rankEl.textContent.trim() : ''; const addressEl = document.querySelector('[class*="address"], [data-test-target="restaurant-address"], span[class*="street"], .address'); const address = addressEl ? addressEl.textContent.trim() : ''; const cuisines = []; const cuisineEls = document.querySelectorAll('[data-test-target="restaurant-detail-info"] a[href*="Cuisine"], [class*="cuisine"] a, [class*="tag"] a, .header_links a'); for (const el of cuisineEls) { const text = el.textContent.trim(); if (text && text.length < 50 && !cuisines.includes(text)) cuisines.push(text); } const hoursEl = document.querySelector('[class*="hours"], [data-test-target="restaurant-hours"], .operatingHours, [class*="operatingHours"]'); const hours = hoursEl ? hoursEl.textContent.trim().substring(0, 200) : ''; const descEl = document.querySelector('[class*="description"], [data-test-target="about-description"], .restaurantDescription, [class*="aboutText"]'); const description = descEl ? descEl.textContent.trim().substring(0, 500) : ''; const dietaryEls = document.querySelectorAll('[class*="dietary"] span, [class*="diet"] a, [class*="DietaryRestriction"]'); const dietary = []; for (const el of dietaryEls) { const text = el.textContent.trim(); if (text && !dietary.includes(text)) dietary.push(text); } const imgEl = document.querySelector('img[class*="photo"], [class*="heroPhoto"] img, .restaurants-detail-hero img'); const image = imgEl ? imgEl.src : ''; return { name: name, rating: rating, review_count: reviewCount, price_range: priceRange, ranking: ranking, cuisines: cuisines, dietary_options: dietary, address: address, hours: hours, description: description, image: image, url: window.location.href }`)

  return result
}
